  static Widget icon(String svgStr, {Color? color, double size = 24, double? strokeWidth}) {
    // If the SVG is using stroke instead of fill, SvgPicture's colorFilter might apply to both
    // For our specific SVGs, they vary (some use fill, some use stroke).
    return SvgPicture.string(
      svgStr,
      width: size,
      height: size,
      colorFilter: color != null ? ColorFilter.mode(color, BlendMode.srcIn) : null,
    );
  }
